function validateAnchorTags(tags) {
  let validValues = new Set(['_blank', '_self', '_parent', '_top']);
  let result = [];
  for (let tag of tags) {
    let target = tag.match(/target=([^ ]+)/)[1];
    result.push(validValues.has(target));
  }
  return result;
}

