class Solution:
  def validateAnchorTags(self, tags):
    valid_values = {'_blank', '_self', '_parent', '_top'}
    result = []
    for tag in tags:
      target = tag.split('target=')[1].split(' ')[0]
      result.append(target in valid_values)
    return result
